import{_ as e,a as t,b as n,c as i,d,e as l,f as r}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as o,o as s,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Tambah Discord Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/discord.md","filePath":"ms-MY/upload/discord.md","lastUpdated":1781962217000}'),p={name:"ms-MY/upload/discord.md"};function m(u,a,k,b,g,D){return s(),c("div",null,[...a[0]||(a[0]=[h('<h1 id="tambah-discord-channel" tabindex="-1">Tambah Discord Channel <a class="header-anchor" href="#tambah-discord-channel" aria-label="Permalink to &quot;Tambah Discord Channel&quot;">​</a></h1><h2 id="perkara-yang-perlu-disediakan" tabindex="-1">Perkara Yang Perlu Disediakan <a class="header-anchor" href="#perkara-yang-perlu-disediakan" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Discord account</td><td>Digunakan untuk mencipta server, channel dan developer application.</td></tr><tr><td>Discord server</td><td>Bot mesti join server sebelum boleh mengakses channel.</td></tr><tr><td>Text channel</td><td>Images dan files akan dihantar ke channel ini.</td></tr><tr><td>Discord Developer Portal</td><td>Digunakan untuk mencipta application, mencipta bot dan mendapatkan <code>Bot Token</code>.</td></tr></tbody></table><h2 id="di-mana-untuk-menambahnya" tabindex="-1">Di Mana Untuk Menambahnya <a class="header-anchor" href="#di-mana-untuk-menambahnya" aria-label="Permalink to &quot;Di Mana Untuk Menambahnya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Pergi ke Upload Settings.</li><li>Klik Add Channel di penjuru kanan atas.</li><li>Pilih <code>Discord</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mesra untuk channel ini, contohnya &quot;Discord Primary&quot;.</td><td>Required</td></tr><tr><td>Bot Token</td><td>Discord bot token.</td><td>Required</td></tr><tr><td>Channel ID</td><td>ID untuk target text channel.</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>Gunakan hanya jika akses Discord CDN tidak stabil. Masukkan full URL termasuk <code>https://</code>.</td><td>Optional</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="_1-cipta-discord-server-dan-text-channel" tabindex="-1">1. Cipta Discord Server dan Text Channel <a class="header-anchor" href="#_1-cipta-discord-server-dan-text-channel" aria-label="Permalink to &quot;1. Cipta Discord Server dan Text Channel&quot;">​</a></h3><ol><li>Buka Discord.</li><li>Cipta server baharu, atau gunakan existing server milik anda.</li><li>Cipta text channel dalam server tersebut.</li></ol><p><img src="'+e+'" alt="Create a server" loading="lazy"></p><h3 id="_2-cipta-bot-dalam-discord-developer-portal" tabindex="-1">2. Cipta Bot Dalam Discord Developer Portal <a class="header-anchor" href="#_2-cipta-bot-dalam-discord-developer-portal" aria-label="Permalink to &quot;2. Cipta Bot Dalam Discord Developer Portal&quot;">​</a></h3><ol><li>Buka Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Klik <code>New Application</code>.</li><li>Masukkan application name dan cipta.</li><li>Buka halaman <code>Bot</code> dari left sidebar.</li><li>Generate atau reset token pada halaman <code>Bot</code>.</li><li>Simpan token.</li></ol><p>Token ini ialah <code>Bot Token</code> yang perlu dimasukkan dalam ImgBed.</p><p><img src="'+t+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-cipta-oauth2-invite-link-dan-install-bot" tabindex="-1">3. Cipta OAuth2 Invite Link dan Install Bot <a class="header-anchor" href="#_3-cipta-oauth2-invite-link-dan-install-bot" aria-label="Permalink to &quot;3. Cipta OAuth2 Invite Link dan Install Bot&quot;">​</a></h3><ol><li>Buka halaman <code>OAuth2</code> dari left sidebar.</li><li>Di bawah scopes, pilih <code>bot</code>.</li><li>Dalam permission area, enable permissions ini:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>Di bahagian bawah halaman, pastikan integration type ialah <code>Guild Install</code>.</li><li>Copy generated URL.</li><li>Buka URL itu dalam browser.</li><li>Pilih target server.</li><li>Lengkapkan authorization flow.</li></ol><p><img src="'+n+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+i+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-enable-developer-mode-dan-copy-channel-id" tabindex="-1">4. Enable Developer Mode dan Copy Channel ID <a class="header-anchor" href="#_4-enable-developer-mode-dan-copy-channel-id" aria-label="Permalink to &quot;4. Enable Developer Mode dan Copy Channel ID&quot;">​</a></h3><ol><li>Klik gear icon di sebelah avatar anda di penjuru kiri bawah Discord.</li><li>Buka Advanced dari left sidebar.</li><li>Enable Developer Mode.</li><li>Kembali ke target text channel.</li><li>Right-click channel name.</li><li>Klik Copy Channel ID.</li></ol><p>Nombor yang disalin ialah <code>Channel ID</code> yang diperlukan oleh ImgBed.</p><p><img src="'+d+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+l+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-isi-discord-channel-dalam-imgbed" tabindex="-1">5. Isi Discord Channel Dalam ImgBed <a class="header-anchor" href="#_5-isi-discord-channel-dalam-imgbed" aria-label="Permalink to &quot;5. Isi Discord Channel Dalam ImgBed&quot;">​</a></h3><p>Kembali ke channel configuration dialog dan isi seperti berikut:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama channel tersuai, contohnya <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token yang disimpan dari halaman <code>Bot</code> dalam Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID yang disalin dari Discord.</td></tr><tr><td>Proxy URL (optional)</td><td>Hanya jika perlu, contohnya <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Klik Save apabila selesai.</p><p><img src="'+r+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="cara-menyemak" tabindex="-1">Cara Menyemak <a class="header-anchor" href="#cara-menyemak" aria-label="Permalink to &quot;Cara Menyemak&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Menyemak</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Selepas save, halaman Upload Settings patut memaparkan Discord channel card.</td></tr><tr><td>Channel boleh diaktifkan</td><td>Active switch patut kekal on.</td></tr><tr><td>Configuration disimpan</td><td>Detail view patut menunjukkan Bot Token dan Channel ID telah disimpan.</td></tr><tr><td>Upload berfungsi</td><td>Upload test image dan pastikan ia muncul dalam target Discord text channel.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cipta Discord server</span></span>
<span class="line"><span>-&gt; Cipta text channel</span></span>
<span class="line"><span>-&gt; Cipta bot dalam Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Simpan Bot Token dari halaman Bot</span></span>
<span class="line"><span>-&gt; Dalam OAuth2, pilih bot, View Channels, Send Messages, Attach Files dan Read Message History</span></span>
<span class="line"><span>-&gt; Copy generated URL dan authorize bot untuk target server</span></span>
<span class="line"><span>-&gt; Pastikan target text channel memberikan permissions yang sama</span></span>
<span class="line"><span>-&gt; Enable Developer Mode</span></span>
<span class="line"><span>-&gt; Right-click target text channel dan copy Channel ID</span></span>
<span class="line"><span>-&gt; Masukkan Bot Token dan Channel ID dalam ImgBed</span></span>
<span class="line"><span>-&gt; Save dan upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const f=o(p,[["render",m]]);export{C as __pageData,f as default};
